import React from "react";
import { useNavigate } from "react-router-dom";
import "./App.css";

function Home() {
  const navigate = useNavigate();

  return (
    <div className="home-container">

      {/* HERO SECTION */}
      <div className="hero">
        <h1>Welcome to our community!!</h1>
        <p>Share posts, help others, and stay connected</p>

        <button className="glow-button" onClick={() => navigate("/help")}>
          Need Local Help?
        </button>
      </div>

      {/* BLOG POSTS SECTION */}
      <div className="blog-section">

        <div className="post">
          <h3>Community Update</h3>
          <p>Helping each other makes society stronger 💚</p>
        </div>

        <div className="post">
          <h3>Announcement</h3>
          <p>LocalHelp platform is now live!</p>
        </div>

        <div className="post">
          <h3>Safety Tip</h3>
          <p>Always verify identity before accepting help requests.</p>
        </div>

      </div>

    </div>
  );
}

export default Home;
